create table dirkspzm32.mde_cfg (
    sid                          varchar2(2 char) not null enable,
    firma_nr                     number(6, 0) not null enable,
    mde_id                       number(*, 0) not null enable,
    res_id                       number(*, 0) not null enable,
    engine_id                    number(*, 0) not null enable,
    opc_connection_id            number(*, 0),
    opc_gruppe                   varchar2(50 char),
    fkt_meldungen                number(*, 0) not null enable,
    fkt_zaehler_1                number(*, 0) not null enable,
    fkt_zaehler_2                number(*, 0) not null enable,
    fkt_zaehler_3                number(*, 0) not null enable,
    fkt_zaehler_4                number(*, 0) not null enable,
    fkt_zaehler_5                number(*, 0) not null enable,
    fkt_zaehler_6                number(*, 0),
    fkt_zaehler_7                number(*, 0),
    fkt_zaehler_8                number(*, 0),
    fkt_zaehler_9                number(*, 0),
    fkt_zaehler_10               number(*, 0),
    fkt_zaehler_11               number(*, 0),
    fkt_zaehler_12               number(*, 0),
    fkt_zaehler_13               number(*, 0),
    fkt_zaehler_14               number(*, 0) not null enable,
    meld_cfg_nr                  number(*, 5) not null enable,
    meld_stat_cfg_nr             number(*, 5) not null enable,
    fkt_zaehler_0                number(*, 0),
    fkt_zaehler_15               number(*, 0),
    fkt_zaehler_16               number(*, 0),
    fkt_zaehler_17               number(*, 0),
    fkt_zaehler_18               number(*, 0),
    fkt_zaehler_19               number(*, 0),
    fkt_zaehler_20               number(*, 0),
    fkt_zaehler_21               number(*, 0),
    fkt_zaehler_22               number(*, 0),
    fkt_zaehler_23               number(*, 0),
    fkt_zaehler_24               number(*, 0),
    fkt_zaehler_25               number(*, 0),
    is_meld_stoer                varchar2(1 char) default 'F' not null enable,
    is_bde_fa_daten              varchar2(1 char) default 'F' not null enable,
    is_meld_stat                 varchar2(1 char) default 'F' not null enable,
    is_zaehler_loggen            varchar2(1 char) default 'F' not null enable,
    zaehler_log_int_ms           number(*, 12) default 0 not null enable,
    is_zaehl_res_schichtwechsel  varchar2(1 char) default 'F' not null enable,
    fa_ist_mengen_int_ms         number(*, 12) default 4000 not null enable,
    computername                 varchar2(100 char),
    mde_connection_typ           varchar2(10 char) default 'OPC',
    mde_com_server               varchar2(15 char),
    communication_queue_sender   varchar2(100 char),
    communication_queue_receiver varchar2(100 char),
    communication_mandant        varchar2(100 char)
);

alter table dirkspzm32.mde_cfg
    add constraint pk_mde_cfg
        primary key ( sid,
                      firma_nr,
                      mde_id )
            using index enable;


